def add_title(slide, title, subtitle=None):
    tx = slide.shapes.add_textbox(Inches(0.4), Inches(0.25), Inches(12.5), Inches(0.5))
    p = tx.text_frame.paragraphs[0]
    p.text = title
    p.font.size = Pt(24)
    p.font.bold = True
    p.font.color.rgb = RGBColor(255,255,255)
    if subtitle:
        st = slide.shapes.add_textbox(Inches(0.42), Inches(0.78), Inches(12.2), Inches(0.3))
        p2 = st.text_frame.paragraphs[0]
        p2.text = subtitle
        p2.font.size = Pt(10)
        p2.font.color.rgb = RGBColor(220,220,220)

def set_bg(slide, color=(17,18,23)):
    fill = slide.background.fill
    fill.solid()
    fill.fore_color.rgb = RGBColor(*color)

def add_kpi(slide, x, y, w, h, label, value, note=""):
    shape = slide.shapes.add_shape(MSO_AUTO_SHAPE_TYPE.ROUNDED_RECTANGLE, Inches(x), Inches(y), Inches(w), Inches(h))
    shape.fill.solid()
    shape.fill.fore_color.rgb = RGBColor(34,37,48)
    shape.line.color.rgb = RGBColor(70,70,80)
    tf = shape.text_frame
    tf.clear()
    p = tf.paragraphs[0]
    p.text = label
    p.font.size = Pt(9)
    p.font.color.rgb = RGBColor(180,180,185)
    p2 = tf.add_paragraph()
    p2.text = value
    p2.font.size = Pt(20)
    p2.font.bold = True
    p2.font.color.rgb = RGBColor(255,255,255)
    if note:
        p3 = tf.add_paragraph()
        p3.text = note
        p3.font.size = Pt(8)
        p3.font.color.rgb = RGBColor(170,170,175)

def make_bar_chart(data, title, ylabel, path):
    labels = [str(x["label"]) for x in data]
    vals = [x["value"] for x in data]
    fig, ax = plt.subplots(figsize=(7, 3.8), dpi=160)
    fig.patch.set_facecolor("#1a1c23")
    ax.set_facecolor("#1a1c23")
    ax.bar(labels, vals)
    ax.set_title(title, color="white", fontsize=12, pad=10)
    ax.set_ylabel(ylabel, color="white", fontsize=9)
    ax.tick_params(colors="white", labelsize=8)
    for spine in ax.spines.values():
        spine.set_color("#444")
    ax.grid(axis="y", color="white", alpha=.08)
    plt.xticks(rotation=20, ha="right")
    plt.tight_layout()
    fig.savefig(path, facecolor=fig.get_facecolor(), bbox_inches="tight")
    plt.close(fig)

def make_gauge(current, target, title, unit, path):
    current = float(current or 0)
    target = float(target or 1)
    pct_raw = (current / target) * 100 if target else 0
    pct_value = max(0, min(pct_raw / 100, 1))

    fig, ax = plt.subplots(figsize=(4.2, 2.8), dpi=180, subplot_kw={"projection": "polar"})
    fig.patch.set_facecolor("#1a1c23")
    ax.set_facecolor("#1a1c23")

    theta_bg = np.linspace(np.pi, 0, 100)
    ax.plot(theta_bg, [1]*len(theta_bg), linewidth=18, solid_capstyle="round", color="#e60000")

    theta_val = np.linspace(np.pi, np.pi - pct_value*np.pi, 100)
    ax.plot(theta_val, [1]*len(theta_val), linewidth=18, solid_capstyle="round", color="#22c55e")

    needle_theta = np.pi - pct_value*np.pi
    ax.plot([needle_theta, needle_theta], [0, .95], linewidth=2.5, color="white")
    ax.scatter([needle_theta], [0], s=30, color="white")

    ax.set_ylim(0, 1.25)
    ax.set_axis_off()

    current_label = f"{current:,.1f}" if current % 1 else f"{current:,.0f}"
    target_label = f"{target:,.1f}" if target % 1 else f"{target:,.0f}"
    pct_label = f"{pct_raw:,.0f}%"

    ax.text(.5, .42, pct_label, transform=ax.transAxes, ha="center", va="center",
            color="white", fontsize=18, fontweight="bold")
    ax.text(.5, .27, title, transform=ax.transAxes, ha="center", va="center",
            color="#d4d4d8", fontsize=9, fontweight="bold")
    ax.text(.5, .13, f"Current: {current_label}{unit}  |  Target: {target_label}{unit}",
            transform=ax.transAxes, ha="center", va="center", color="#a1a1aa", fontsize=7.5)

    plt.tight_layout(pad=.3)
    fig.savefig(path, facecolor=fig.get_facecolor(), bbox_inches="tight")
    plt.close(fig)


# ---------------- EXECUTIVE POWERPOINT EXPORT HELPERS ----------------

PPT_DARK = (6, 19, 28)
PPT_BG = PPT_DARK
PPT_PANEL = (10, 30, 42)
PPT_PANEL_2 = (13, 38, 52)
PPT_LINE = (65, 95, 115)
PPT_RED = (230, 0, 0)
PPT_GREEN = (25, 200, 74)
PPT_AMBER = (255, 196, 0)
PPT_BLUE = (80, 160, 255)
PPT_WHITE = (245, 248, 250)
PPT_MUTED = (175, 190, 202)
PPT_TRACK = (50, 65, 78)
PPT_TABLE_ALT = (13, 34, 48)
PPT_TABLE_ALT2 = (9, 28, 40)
PPT_VALUE = (31, 255, 83)
PPT_IS_LIGHT = False

def apply_ppt_theme(theme='dark'):
    """Set PPT export colours to match the dashboard theme."""
    global PPT_BG, PPT_PANEL, PPT_PANEL_2, PPT_LINE, PPT_WHITE, PPT_MUTED, PPT_TRACK, PPT_TABLE_ALT, PPT_TABLE_ALT2, PPT_VALUE, PPT_IS_LIGHT
    PPT_IS_LIGHT = str(theme or 'dark').lower() == 'light'
    if PPT_IS_LIGHT:
        PPT_BG = (245, 247, 251)
        PPT_PANEL = (255, 255, 255)
        PPT_PANEL_2 = (241, 244, 248)
        PPT_LINE = (210, 217, 227)
        PPT_WHITE = (17, 24, 39)
        PPT_MUTED = (86, 100, 118)
        PPT_TRACK = (218, 224, 235)
        PPT_TABLE_ALT = (255, 255, 255)
        PPT_TABLE_ALT2 = (245, 247, 251)
        PPT_VALUE = (22, 101, 52)
    else:
        PPT_BG = PPT_DARK
        PPT_PANEL = (10, 30, 42)
        PPT_PANEL_2 = (13, 38, 52)
        PPT_LINE = (65, 95, 115)
        PPT_WHITE = (245, 248, 250)
        PPT_MUTED = (175, 190, 202)
        PPT_TRACK = (50, 65, 78)
        PPT_TABLE_ALT = (13, 34, 48)
        PPT_TABLE_ALT2 = (9, 28, 40)
        PPT_VALUE = (31, 255, 83)


def _rgb(t):
    return RGBColor(int(t[0]), int(t[1]), int(t[2]))


def _fmt_money(v):
    try:
        return f"R{float(v)/1_000_000:,.1f}m"
    except Exception:
        return "R0.0m"


def _fmt_num(v):
    try:
        return f"{float(v):,.0f}"
    except Exception:
        return "0"


def _pct_value(g):
    try:
        return float(g.get('pct', 0))
    except Exception:
        return 0.0


def ppt_text(slide, x, y, w, h, text, size=14, bold=False, color=PPT_WHITE):
    box = slide.shapes.add_textbox(Inches(x), Inches(y), Inches(w), Inches(h))
    tf = box.text_frame
    tf.clear()
    tf.margin_left = Inches(0.05)
    tf.margin_right = Inches(0.05)
    tf.margin_top = Inches(0.03)
    tf.margin_bottom = Inches(0.03)
    p = tf.paragraphs[0]
    p.text = str(text)
    p.font.size = Pt(size)
    p.font.bold = bold
    p.font.color.rgb = _rgb(color)
    return box


def ppt_header(slide, title, subtitle=""):
    set_bg(slide, PPT_BG)
    bar = slide.shapes.add_shape(MSO_AUTO_SHAPE_TYPE.RECTANGLE, Inches(0), Inches(0), Inches(13.333), Inches(0.13))
    bar.fill.solid(); bar.fill.fore_color.rgb = _rgb(PPT_RED); bar.line.color.rgb = _rgb(PPT_RED)
    # Keep title area clear and place the real Vodacom logo in the top-right.
    ppt_text(slide, 0.45, 0.32, 9.5, 0.45, title, 26, True)
    if subtitle:
        ppt_text(slide, 0.47, 0.80, 10.7, 0.28, subtitle, 12, False, PPT_MUTED)
    ensure_vodacom_logo()
    if VODACOM_LOGO_FILE.exists():
        slide.shapes.add_picture(str(VODACOM_LOGO_FILE), Inches(10.55), Inches(0.22), Inches(2.35), Inches(0.64))


def ppt_card(slide, x, y, w, h, title, value, note="", accent=PPT_GREEN, value_size=28):
    shape = slide.shapes.add_shape(MSO_AUTO_SHAPE_TYPE.ROUNDED_RECTANGLE, Inches(x), Inches(y), Inches(w), Inches(h))
    shape.fill.solid(); shape.fill.fore_color.rgb = _rgb(PPT_PANEL); shape.line.color.rgb = _rgb(PPT_LINE)
    strip = slide.shapes.add_shape(MSO_AUTO_SHAPE_TYPE.RECTANGLE, Inches(x), Inches(y), Inches(0.07), Inches(h))
    strip.fill.solid(); strip.fill.fore_color.rgb = _rgb(accent); strip.line.color.rgb = _rgb(accent)
    ppt_text(slide, x+0.18, y+0.16, w-0.28, 0.28, title, 11, False, PPT_MUTED)
    ppt_text(slide, x+0.18, y+0.49, w-0.28, 0.58, value, value_size, True, PPT_WHITE)
    if note:
        ppt_text(slide, x+0.18, y+1.12, w-0.28, 0.36, note, 10.5, False, PPT_MUTED)
    return shape


def ppt_progress(slide, x, y, w, h, pct, label, current, target):
    pct = max(0, min(float(pct or 0), 100))
    color = PPT_GREEN if pct >= 80 else (PPT_AMBER if pct >= 50 else PPT_RED)
    ppt_text(slide, x, y-0.34, w*0.62, 0.28, label, 14, True)
    ppt_text(slide, x+w-1.0, y-0.34, 1.0, 0.28, f"{pct:.0f}%", 14, True)
    bg = slide.shapes.add_shape(MSO_AUTO_SHAPE_TYPE.ROUNDED_RECTANGLE, Inches(x), Inches(y), Inches(w), Inches(h))
    bg.fill.solid(); bg.fill.fore_color.rgb = _rgb(PPT_TRACK); bg.line.color.rgb = _rgb(PPT_TRACK)
    fg_w = max(0.05, w * pct/100)
    fg = slide.shapes.add_shape(MSO_AUTO_SHAPE_TYPE.ROUNDED_RECTANGLE, Inches(x), Inches(y), Inches(fg_w), Inches(h))
    fg.fill.solid(); fg.fill.fore_color.rgb = _rgb(color); fg.line.color.rgb = _rgb(color)
    ppt_text(slide, x, y+h+0.07, w, 0.26, f"Current: {current}   |   Target: {target}", 10.5, False, PPT_MUTED)


def ppt_domain_bars(slide, domain_data):
    max_val = max([d['value'] for d in domain_data] + [1])
    y = 1.55
    for d in domain_data:
        ppt_text(slide, 0.75, y-0.02, 3.0, 0.35, d['label'], 15, True)
        bg = slide.shapes.add_shape(MSO_AUTO_SHAPE_TYPE.ROUNDED_RECTANGLE, Inches(3.65), Inches(y+0.03), Inches(7.4), Inches(0.26))
        bg.fill.solid(); bg.fill.fore_color.rgb = _rgb(PPT_TRACK); bg.line.color.rgb = _rgb(PPT_TRACK)
        bw = max(0.08, 7.4 * d['value']/max_val)
        fg = slide.shapes.add_shape(MSO_AUTO_SHAPE_TYPE.ROUNDED_RECTANGLE, Inches(3.65), Inches(y+0.03), Inches(bw), Inches(0.26))
        fg.fill.solid(); fg.fill.fore_color.rgb = _rgb(PPT_GREEN); fg.line.color.rgb = _rgb(PPT_GREEN)
        ppt_text(slide, 11.25, y-0.02, 1.4, 0.35, _fmt_money(d['value']), 15, True)
        y += 0.85


def _font(size=24, bold=False):
    candidates = [
        '/usr/share/fonts/truetype/dejavu/DejaVuSans-Bold.ttf' if bold else '/usr/share/fonts/truetype/dejavu/DejaVuSans.ttf',
        '/usr/share/fonts/truetype/liberation2/LiberationSans-Bold.ttf' if bold else '/usr/share/fonts/truetype/liberation2/LiberationSans-Regular.ttf',
        'C:/Windows/Fonts/arialbd.ttf' if bold else 'C:/Windows/Fonts/arial.ttf',
    ]
    for p in candidates:
        try:
            return ImageFont.truetype(p, size)
        except Exception:
            pass
    return ImageFont.load_default()


def _wrap(draw, text, font, width_px):
    words = str(text or '').replace('\n', ' ').split()
    lines, cur = [], ''
    for word in words:
        test = (cur + ' ' + word).strip()
        if draw.textbbox((0,0), test, font=font)[2] <= width_px or not cur:
            cur = test
        else:
            lines.append(cur); cur = word
    if cur: lines.append(cur)
    return lines


def _draw_wrap(draw, x, y, text, font, fill, width_px, max_lines=2, gap=3):
    lines = _wrap(draw, text, font, width_px)[:max_lines]
    for line in lines:
        draw.text((x, y), line, font=font, fill=fill)
        y += font.size + gap


def _status_color(status):
    s = str(status).lower()
    if 'production' in s: return (31,181,85)
    if 'progress' in s or 'prototype' in s: return (28,130,215)
    if 'planned' in s: return (120,130,145)
    return (245,177,66)


def _impact_color(impact):
    s = str(impact).lower()
    if 'very' in s: return (230,0,0)
    if 'high' in s: return (255,176,0)
    if 'medium' in s: return (255,220,0)
    return (104,196,67)


def _reuse_color(reuse):
    try: r = int(float(reuse))
    except Exception: r = 0
    if r >= 5: return (24,200,74)
    if r == 4: return (77,195,105)
    if r == 3: return (255,214,0)
    if r == 2: return (255,176,0)
    return (240,52,40)


def table_image(title, subtitle, headers, rows, widths, path, max_lines=2, font_size=22, row_h=92):
    W, H = 1920, 1080
    img = Image.new('RGB', (W,H), PPT_BG)
    draw = ImageDraw.Draw(img)
    for i in range(0, H, 6):
        if PPT_IS_LIGHT:
            shade = int(245 - 8*(i/H)); draw.line([(0,i),(W,i)], fill=(shade, shade+1 if shade < 254 else shade, 251))
        else:
            shade = int(16 + 18*(i/H)); draw.line([(0,i),(W,i)], fill=(4, shade, 30))
    title_f, sub_f = _font(50, True), _font(24, False)
    hdr_f, cell_f, cell_b = _font(22, True), _font(font_size, False), _font(font_size, True)
    small_f = _font(max(17, font_size-3), False)
    draw.text((55, 38), title, font=title_f, fill=PPT_WHITE)
    if subtitle: draw.text((57, 100), subtitle, font=sub_f, fill=PPT_MUTED)
    # Use the real Vodacom logo instead of decorative red circle / text.
    try:
        if VODACOM_LOGO_FILE.exists():
            logo = Image.open(VODACOM_LOGO_FILE).convert("RGBA")
            logo.thumbnail((360, 110), Image.LANCZOS)
            img.paste(logo, (W - logo.width - 55, 35), logo)
    except Exception:
        pass
    x0, y0 = 45, 165
    table_w = sum(widths)
    header_h = 54
    max_rows = int((H-y0-95-header_h)/row_h)
    rows = rows[:max_rows]
    xs=[x0]
    for w in widths[:-1]: xs.append(xs[-1]+w)
    draw.rounded_rectangle((x0-10,y0-12,x0+table_w+10,y0+header_h+row_h*len(rows)+20), radius=20, fill=PPT_PANEL, outline=PPT_LINE, width=2)
    draw.rectangle((x0,y0,x0+table_w,y0+header_h), fill=PPT_RED)
    for i,h in enumerate(headers): _draw_wrap(draw, xs[i]+10, y0+14, h, hdr_f, PPT_WHITE, widths[i]-20, 1)
    for r,row in enumerate(rows):
        y=y0+header_h+r*row_h
        fill = PPT_TABLE_ALT if r%2==0 else PPT_TABLE_ALT2
        draw.rectangle((x0,y,x0+table_w,y+row_h), fill=fill)
        draw.line((x0,y,x0+table_w,y), fill=PPT_LINE, width=1)
        xx=x0
        for w in widths:
            draw.line((xx,y,xx,y+row_h), fill=PPT_LINE, width=1); xx += w
        for c,val in enumerate(row):
            header = str(headers[c]).lower(); x=xs[c]; w=widths[c]
            if 'status' in header:
                col = _status_color(val); draw.rounded_rectangle((x+10,y+18,x+w-10,y+52), radius=13, fill=col)
                _draw_wrap(draw, x+17,y+24,val,small_f,PPT_WHITE,w-34,1)
            elif 'impact' in header:
                col = _impact_color(val); draw.rounded_rectangle((x+10,y+18,x+w-10,y+52), radius=13, fill=col)
                _draw_wrap(draw, x+17,y+24,val,small_f,(0,0,0) if col[1]>160 else PPT_WHITE,w-34,1)
            elif 'reuse' in header:
                col = _reuse_color(val); draw.ellipse((x+25,y+16,x+65,y+56), fill=col)
                draw.text((x+38,y+23), str(val), font=cell_b, fill=(0,0,0))
            elif 'value' in header or 'benefit' in header or 'roi' in header:
                _draw_wrap(draw,x+10,y+20,val,cell_b,PPT_VALUE,w-20,1)
            else:
                _draw_wrap(draw,x+10,y+12,val,cell_b if c==0 else cell_f,PPT_WHITE if c!=1 else PPT_MUTED,w-20,max_lines)
    draw.text((55,H-50), "Source: ASOC AI dashboard use-case register", font=_font(17, False), fill=PPT_MUTED)
    img.save(path)


def chunks(items, size):
    for i in range(0, len(items), size):
        yield i, items[i:i+size]

@app.get("/export/pptx")
async def export_pptx(theme: str = "dark", user=Depends(require_login)):
    apply_ppt_theme(theme)
    cases = load_use_cases()
    settings = load_settings()
    s = summary(cases, settings)
    gauges = gauge_values(s, settings)
    active_year = gauges.get("year", settings.get("active_year", "FY27"))
    prs = Presentation()
    prs.slide_width = Inches(13.333)
    prs.slide_height = Inches(7.5)

    # 1. Executive Summary
    slide = prs.slides.add_slide(prs.slide_layouts[6]); ppt_header(slide, "ASOC AI Benefits Realisation Portfolio", f"{active_year} Executive View · Exported {datetime.date.today().isoformat()}")
    ppt_card(slide, 0.55, 1.30, 2.9, 1.55, "Benefits Realised", _fmt_money(s["annual_value"]), f"{gauges['annual_benefits']['pct']}% of target")
    ppt_card(slide, 3.65, 1.30, 2.9, 1.55, "Hours Returned", _fmt_num(s["hours_saved"]), f"{gauges['hours_saved']['pct']}% of target")
    ppt_card(slide, 6.75, 1.30, 2.9, 1.55, "Portfolio ROI", f"{s['portfolio_roi']}%", f"Target {gauges['roi']['target']}%")
    ppt_card(slide, 9.85, 1.30, 2.9, 1.55, "Reusable Portfolio", f"{s['reusable_percent']}%", f"{s['reusable_count']} of {s['active_use_cases']} use cases")
    gap = gauges["annual_benefits"]["target"] - s["annual_value"]
    status = "ON TRACK" if gauges["annual_benefits"]["pct"] >= 75 else "ATTENTION REQUIRED"
    ppt_card(slide, 0.65, 3.55, 5.85, 1.25, "Portfolio Status", status, f"Gap to FY target: {_fmt_money(max(gap,0))}", PPT_GREEN if status == "ON TRACK" else PPT_AMBER, 25)
    ppt_card(slide, 6.85, 3.55, 5.85, 1.25, "Leadership Focus", "Scale reusable AI", "Agentic API · Auto Config · Self-Healing · Unified Intelligence", PPT_RED, 24)
    ppt_text(slide, 0.65, 6.35, 11.8, 0.35, "Generated from the ASOC AI dashboard data and Admin-configured targets.", 12, False, PPT_MUTED)

    # 2. Benefits Realisation
    slide = prs.slides.add_slide(prs.slide_layouts[6]); ppt_header(slide, "Benefits Realisation", "Current value against FY target")
    ppt_text(slide, 0.8, 1.25, 4.8, 0.42, "FY Benefits Target", 18, True)
    ppt_text(slide, 0.8, 1.82, 4.8, 0.85, _fmt_money(gauges['annual_benefits']['target']), 42, True)
    ppt_progress(slide, 0.8, 3.15, 11.55, 0.38, gauges['annual_benefits']['pct'], "Benefits Realised", _fmt_money(s['annual_value']), _fmt_money(gauges['annual_benefits']['target']))
    ppt_card(slide, 0.8, 4.35, 3.6, 1.15, "Current", _fmt_money(s['annual_value']), "Benefits realised")
    ppt_card(slide, 4.85, 4.35, 3.6, 1.15, "Remaining Gap", _fmt_money(max(gap,0)), "To meet target", PPT_AMBER)
    ppt_card(slide, 8.9, 4.35, 3.4, 1.15, "Achievement", f"{gauges['annual_benefits']['pct']:.0f}%", "Target attainment")

    # 3. Portfolio Health
    slide = prs.slides.add_slide(prs.slide_layouts[6]); ppt_header(slide, "Portfolio Health", "Target attainment across core executive KPIs")
    health = [
        ("Benefits Realisation", gauges['annual_benefits'], _fmt_money(gauges['annual_benefits']['current']), _fmt_money(gauges['annual_benefits']['target'])),
        ("Hours Returned", gauges['hours_saved'], _fmt_num(gauges['hours_saved']['current']), _fmt_num(gauges['hours_saved']['target'])),
        ("Production Adoption", gauges['production_use_cases'], _fmt_num(gauges['production_use_cases']['current']), _fmt_num(gauges['production_use_cases']['target'])),
        ("TMF Maturity", gauges['tmf_maturity'], f"L{gauges['tmf_maturity']['current']}", f"L{gauges['tmf_maturity']['target']}"),
        ("Reuse", gauges['reusable_percent'], f"{gauges['reusable_percent']['current']}%", f"{gauges['reusable_percent']['target']}%"),
        ("ROI", gauges['roi'], f"{gauges['roi']['current']}%", f"{gauges['roi']['target']}%"),
    ]
    y=1.35
    for label,g,current,target in health:
        ppt_progress(slide, 1.0, y, 10.9, 0.30, g['pct'], label, current, target); y += 0.82

    # 4. Top use cases cards
    slide = prs.slides.add_slide(prs.slide_layouts[6]); ppt_header(slide, "Top Value AI Use Cases", "Highest annual benefit contribution")
    top10 = sorted(cases, key=lambda x: as_number(x.get('annual_value',0)), reverse=True)[:10]
    for idx,item in enumerate(top10):
        col=idx%5; row=idx//5; x=0.55+col*2.52; y=1.35+row*1.62
        title=item.get('name','')
        if len(title)>42: title=title[:39]+'...'
        accent = PPT_GREEN if as_number(item.get('reuse_score',0)) >= 4 else PPT_AMBER
        ppt_card(slide, x, y, 2.35, 1.35, title, _fmt_money(item.get('annual_value',0)), f"{item.get('domain','')} · Reuse {item.get('reuse_score','')}", accent, 21)

    # 5. Domain contribution
    slide = prs.slides.add_slide(prs.slide_layouts[6]); ppt_header(slide, "Domain Contribution", "Portfolio value by ASOC domain")
    ppt_domain_bars(slide, group_by(cases, 'domain', 'annual_value'))

    # 6. TMF maturity journey
    slide = prs.slides.add_slide(prs.slide_layouts[6]); ppt_header(slide, "TM Forum Autonomous Network Journey", "ASOC AI progression from assistive to closed-loop automation")
    levels=[('L1','Assist','Ask ASOC\nCoreXplore'),('L2','Augment','Ask Katlego\nSOC Assistant'),('L3','Automate','Fault Localisation\nConfig Verification'),('L4','Closed Loop','Self-Healing RAN\nAgentic API'),('L5','Autonomous','Digital Twin\nZero Touch')]
    for i,(lvl,title,examples) in enumerate(levels):
        x=0.55+i*2.52
        ppt_card(slide,x,1.7,2.25,2.05,lvl,title,examples,PPT_GREEN if i<4 else PPT_AMBER,28)
        if i<4: ppt_text(slide,x+2.16,2.46,0.35,0.25,'➜',22,True,PPT_RED)
    ppt_progress(slide,1.1,5.35,10.9,0.30,gauges['tmf_maturity']['pct'],'Current maturity progress',f"L{gauges['tmf_maturity']['current']}",f"L{gauges['tmf_maturity']['target']}")

    # 7. Cross-market reuse
    slide = prs.slides.add_slide(prs.slide_layouts[6]); ppt_header(slide, "Cross-Market Reuse", "Build Once, Deploy Many value story")
    ppt_card(slide,0.65,1.35,3.3,1.45,"Reusable Use Cases",f"{s['reusable_count']} / {s['active_use_cases']}",f"{s['reusable_percent']}% of portfolio")
    ppt_card(slide,4.25,1.35,3.3,1.45,"Reuse Threshold","Score ≥ 4","Cross-domain or cross-market")
    ppt_card(slide,7.85,1.35,4.2,1.45,"Strategic Markets","ZA · TZ · MZ · LS · VOIS","Deploy once, configure many")
    rows=[[str(r['score']), r['level'], r['meaning']] for r in REUSE_LEGEND]
    path = BASE_DIR/'static'/'ppt_reuse_table.png'
    table_image('Reuse Score Model', 'Cross-domain and cross-market reuse scoring', ['Score','Level','Meaning'], rows, [180,420,1260], path, max_lines=2, font_size=24, row_h=92)
    slide.shapes.add_picture(str(path), Inches(0), Inches(3.15), Inches(13.333), Inches(4.35))

    # 8. Executive Decisions
    slide = prs.slides.add_slide(prs.slide_layouts[6]); ppt_header(slide, "Executive Decisions Required", "Leadership actions to convert AI activity into measurable value")
    y=1.25
    for i,decision in enumerate(settings.get('executive_decisions',[])[:6],1):
        ppt_card(slide,0.8,y,11.8,0.72,f"Decision {i}",decision,"",PPT_RED,17); y+=0.85

    # Detailed register split across slides: 5 rows per slide for readability
    sorted_cases=sorted(cases,key=lambda x:as_number(x.get('annual_value',0)),reverse=True)
    for idx,chunk in chunks(sorted_cases,5):
        rows=[]
        for item in chunk:
            rows.append([item.get('id',''), item.get('name',''), item.get('domain',''), item.get('status',''), item.get('kpi',''), _fmt_money(item.get('annual_value',0)), str(item.get('reuse_score',''))])
        path=BASE_DIR/'static'/f'ppt_register_exec_{idx}.png'
        table_image('Full AI Use-Case Register', f'Rows {idx+1}-{idx+len(chunk)} of {len(sorted_cases)} · readable executive appendix', ['ID','Use Case','Domain','Status','KPI / Benefit Driver','Value','Reuse'], rows, [130,410,250,160,650,150,100], path, max_lines=3, font_size=24, row_h=128)
        slide=prs.slides.add_slide(prs.slide_layouts[6]); slide.shapes.add_picture(str(path), Inches(0), Inches(0), Inches(13.333), Inches(7.5))

    # Domain detail slides: 5 rows max per domain slide, chunk where needed
    domains=[]
    for c in cases:
        if c.get('domain') not in domains: domains.append(c.get('domain'))
    for domain in domains:
        dc=[c for c in sorted_cases if c.get('domain')==domain]
        for idx,chunk in chunks(dc,5):
            rows=[]
            for item in chunk:
                rows.append([item.get('name',''), item.get('tmf_level',''), item.get('impact',''), item.get('status',''), item.get('sponsor',''), item.get('technical_owner',''), _fmt_money(item.get('annual_value',0)), str(item.get('reuse_score',''))])
            path=BASE_DIR/'static'/f"ppt_domain_exec_{domain.replace(' ','_')}_{idx}.png"
            table_image(f'Domain Detail · {domain}', f'{len(dc)} use cases · total value {_fmt_money(sum(as_number(x.get("annual_value",0)) for x in dc))}', ['Use Case','TMF','Impact','Status','Sponsor','Tech Owner','Value','Reuse'], rows, [410,90,130,150,230,260,145,95], path, max_lines=2, font_size=24, row_h=128)
            slide=prs.slides.add_slide(prs.slide_layouts[6]); slide.shapes.add_picture(str(path), Inches(0), Inches(0), Inches(13.333), Inches(7.5))

    # KPI baseline/current/target slides: 4 rows per slide
    for idx,chunk in chunks(sorted_cases,4):
        rows=[]
        for item in chunk:
            rows.append([item.get('id',''), item.get('name',''), item.get('strategic_outcome',''), item.get('baseline_kpi',''), item.get('current_kpi',''), item.get('target_kpi','')])
        path=BASE_DIR/'static'/f'ppt_kpi_exec_{idx}.png'
        table_image('KPI Baseline / Current / Target', f'Rows {idx+1}-{idx+len(chunk)} of {len(sorted_cases)} · operational benefit tracking', ['ID','Use Case','Strategic Outcome','Baseline KPI','Current KPI','Target KPI'], rows, [120,315,430,330,330,390], path, max_lines=3, font_size=22, row_h=150)
        slide=prs.slides.add_slide(prs.slide_layouts[6]); slide.shapes.add_picture(str(path), Inches(0), Inches(0), Inches(13.333), Inches(7.5))

    output=io.BytesIO()
    prs.save(output)
    output.seek(0)
    return StreamingResponse(output, media_type='application/vnd.openxmlformats-officedocument.presentationml.presentation', headers={'Content-Disposition':'attachment; filename=asoc_ai_executive_reporting_pack.pptx'})



@app.get("/profile", response_class=HTMLResponse)
async def profile(request: Request, error: str = "", success: str = "", user=Depends(require_login)):
    return templates.TemplateResponse("profile.html", {"request": request, "user": user, "error": error, "success": success})

@app.post("/profile/save")
async def save_profile(
    request: Request,
    display_name: str = Form(""),
    email: str = Form(""),
    current_password: str = Form(""),
    new_password: str = Form(""),
    confirm_password: str = Form(""),
    user=Depends(require_login)
):
    users = load_users()
    existing = next((u for u in users if u.get("username") == user.get("username")), None)
    if not existing:
        return redirect_with_error("/profile", "User profile not found")
    existing["display_name"] = display_name.strip() or existing.get("username")
    existing["email"] = email.strip()
    if new_password.strip():
        if not _verify_password(current_password, existing.get("password_hash", "")):
            return redirect_with_error("/profile", "Current password is incorrect")
        if new_password != confirm_password:
            return redirect_with_error("/profile", "New password and confirm password do not match")
        if len(new_password) < 8:
            return redirect_with_error("/profile", "Password must be at least 8 characters")
        existing["password_hash"] = _password_hash(new_password)
    save_users(users)
    return RedirectResponse("/profile?success=Profile%20updated", status_code=303)

