@app.post("/admin/users/save")
async def save_user(
    request: Request,
    username: str = Form(...),
    display_name: str = Form(""),
    email: str = Form(""),
    role: str = Form(...),
    password: str = Form(""),
    active: str = Form("true"),
    domains: list[str] = Form([]),
    user=Depends(require_super_admin)
):
    username = username.strip().lower()
    if role not in ["viewer", "admin", "super_admin"]:
        return redirect_with_error("/admin/users", "Invalid role")
    selected_domains = normalise_domains(domains)
    if role != "admin":
        selected_domains = []
    users = load_users()
    existing = next((u for u in users if u.get("username") == username), None)
    if existing:
        super_admins = [u for u in users if u.get("role") == "super_admin" and u.get("active", True)]
        is_last_super_admin = existing.get("role") == "super_admin" and len(super_admins) <= 1
        if is_last_super_admin and role != "super_admin":
            return redirect_with_error("/admin/users", "Cannot remove super_admin role from the last super admin")
        if is_last_super_admin and active != "true":
            return redirect_with_error("/admin/users", "Cannot deactivate the last super admin")
        existing["display_name"] = display_name.strip() or username
        existing["email"] = email.strip()
        existing["role"] = role
        existing["active"] = active == "true"
        existing["domains"] = selected_domains
        if password.strip():
            if len(password.strip()) < 8:
                return redirect_with_error("/admin/users", "Password must be at least 8 characters")
            existing["password_hash"] = _password_hash(password.strip())
    else:
        if not password.strip():
            return redirect_with_error("/admin/users", "Password required for new users")
        if len(password.strip()) < 8:
            return redirect_with_error("/admin/users", "Password must be at least 8 characters")
        users.append({
            "username": username,
            "display_name": display_name.strip() or username,
            "email": email.strip(),
            "role": role,
            "password_hash": _password_hash(password.strip()),
            "active": active == "true",
            "domains": selected_domains
        })
    save_users(users)
    return RedirectResponse("/admin/users", status_code=303)

@app.post("/admin/users/delete")
async def delete_user(username: str = Form(...), user=Depends(require_super_admin)):
    username = username.strip().lower()
    if username == user.get("username"):
        return redirect_with_error("/admin/users", "You cannot delete your own account while logged in")
    users_before = load_users()
    target = next((u for u in users_before if u.get("username") == username), None)
    super_admins = [u for u in users_before if u.get("role") == "super_admin" and u.get("active", True)]
    if target and target.get("role") == "super_admin" and len(super_admins) <= 1:
        return redirect_with_error("/admin/users", "Cannot delete the last super admin")
    users = [u for u in users_before if u.get("username") != username]
    save_users(users)
    return RedirectResponse("/admin/users", status_code=303)

